export function buildEnvExample(f) {
    const lines = [];
    lines.push("# Generated by create-templaite — remove unused sections.", "");
    lines.push("# Public site origin — metadataBase, sitemap, robots, OG URLs", 'NEXT_PUBLIC_APP_URL="http://localhost:3000"', "");
    if (f.auth) {
        lines.push("# Better Auth", 'BETTER_AUTH_SECRET=""', 'BETTER_AUTH_URL="http://localhost:3000"', "");
    }
    if (f.database) {
        lines.push("# Postgres — pooled URL at runtime; direct URL for Prisma migrate", 'DATABASE_URL="postgresql://user:pass@host:5432/db?sslmode=require"', 'DIRECT_URL="postgresql://user:pass@host:5432/db?sslmode=require"', "");
    }
    if (f.googleOAuth) {
        lines.push("# Google OAuth — optional", "# GOOGLE_CLIENT_ID=", "# GOOGLE_CLIENT_SECRET=", "");
    }
    if (f.resend) {
        lines.push("# Resend — optional transactional email", "# RESEND_API_KEY=", '# EMAIL_FROM="App <onboarding@resend.dev>"', "# ALLOW_TEST_EMAIL=true", "");
    }
    if (f.payments) {
        lines.push("# Polar — optional", "# POLAR_ACCESS_TOKEN=", "# POLAR_SERVER=production", "# POLAR_WEBHOOK_SECRET=", "# POLAR_CHECKOUT_PRODUCT_ID=", "# POLAR_CHECKOUT_SLUG=", "");
    }
    if (f.aiChat) {
        lines.push("# AI chat — Vercel AI Gateway and/or OpenAI", "# AI_GATEWAY_API_KEY=", "# OPENAI_API_KEY=", "");
    }
    if (f.notionBlog) {
        lines.push("# Notion blog — optional", "# NOTION_TOKEN=", "# NOTION_BLOG_DATABASE_ID=", "");
    }
    return lines.join("\n");
}
